import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"5/ AI-generated code often works, but the scarce skill is judgment — @stephzhan","description":"","frontmatter":{"title":"5/ AI-generated code often works, but the scarce skill is judgment — @stephzhan","author":"Stephanie Zhan（@stephzhan）","date":"2026-04-29T00:00:00.000Z","source":"https://x.com/stephzhan/status/2049518670767075818","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@stephzhan-075818.md","filePath":"research/tweets/2026-04-29-@stephzhan-075818.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-04-29-@stephzhan-075818.md"};function n(d,t,i,h,l,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_5-ai-generated-code-often-works-but-the-scarce-skill-is-judgment-—-stephzhan" tabindex="-1">5/ AI-generated code often works, but the scarce skill is judgment — @stephzhan <a class="header-anchor" href="#_5-ai-generated-code-often-works-but-the-scarce-skill-is-judgment-—-stephzhan" aria-label="Permalink to &quot;5/ AI-generated code often works, but the scarce skill is judgment — @stephzhan&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/stephzhan/status/2049518670767075818" target="_blank" rel="noreferrer">https://x.com/stephzhan/status/2049518670767075818</a><strong>作者</strong>：Stephanie Zhan（@stephzhan） <strong>發布日期</strong>：2026-04-29 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：23 likes · 1 retweets · 11 bookmarks · 2650 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>5/ AI generated code often works.</p><p>That does not mean it is good.</p><p>It can be bloated, copy-paste heavy, brittle, and awkwardly abstracted.</p><p>The scarce skill is still judgment: knowing when to simplify, when to delete, when the abstraction is wrong, and when &quot;working&quot; is not enough.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：AI 生成的程式碼「可以跑」不等於「好的」；稀缺的判斷力是知道何時簡化、何時刪除、何時抽象是錯的。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>AI 產生程式碼的四個常見缺陷：bloated / copy-paste heavy / brittle / awkwardly abstracted</li><li>稀缺技能：判斷力 — 「何時簡化」「何時刪除」「何時抽象是錯的」「何時 working 不夠」</li><li>Working ≠ Good：這是 agentic engineering 與 vibe coding 的本質區別之一</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>四個 AI 程式碼缺陷：bloated / copy-paste heavy / brittle / awkwardly abstracted</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>這是 cc-workspace <code>core.md</code> 外科刀原則的第三方驗證：AI 傾向過度工程（bloated/copy-paste）正是 Karpathy 原則要防止的</li><li>「When working is not enough」與 cc-workspace 的 healthcheck + deep-review 三軸審查直接對應</li><li>稀缺判斷力的四個維度可直接補充 <code>karpathy-principles.md</code> §Simplicity First 的反模式清單</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>四個 AI 程式碼缺陷可補充 deep-review checklist 或 karpathy-principles.md</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>精確點出 working vs. good 的區別，有具體的四分類</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>廣泛實踐觀察，無量化</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>bloated/brittle/awkward abstraction 有工程具體性</td></tr><tr><td>E. 泛化性 (15%)</td><td>9/10</td><td>所有 AI 輔助程式碼場景皆適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.6/10</strong></td><td>7×0.3+6×0.2+5×0.2+6×0.15+9×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：總分 6.6；四個 AI 程式碼缺陷（bloated/copy-paste/brittle/awkward abstraction）可補充至 <code>karpathy-principles.md</code> §Simplicity First 反模式列表</p>',21)])])}const u=e(s,[["render",n]]);export{g as __pageData,u as default};
